import{_ as a,o,c as r,ag as t}from"./chunks/framework.1N8rnUr9.js";const p=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md","lastUpdated":1775715475000}'),i={name:"faq.md"};function s(n,e,l,h,d,c){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">‚Äã</a></h1><p>Commonly asked questions about TubeBay.</p><h2 id="requirements-compatibility" tabindex="-1">Requirements &amp; Compatibility <a class="header-anchor" href="#requirements-compatibility" aria-label="Permalink to &quot;Requirements &amp; Compatibility&quot;">‚Äã</a></h2><h3 id="do-i-need-woocommerce" tabindex="-1">Do I need WooCommerce? <a class="header-anchor" href="#do-i-need-woocommerce" aria-label="Permalink to &quot;Do I need WooCommerce?&quot;">‚Äã</a></h3><p>Yes. TubeBay is a WooCommerce extension and <strong>will not function</strong> without WooCommerce installed and active. The plugin checks for WooCommerce on activation and will display a notice if it&#39;s missing.</p><h3 id="which-wordpress-version-is-required" tabindex="-1">Which WordPress version is required? <a class="header-anchor" href="#which-wordpress-version-is-required" aria-label="Permalink to &quot;Which WordPress version is required?&quot;">‚Äã</a></h3><p>TubeBay requires <strong>WordPress 5.8 or later</strong>. We recommend always running the latest stable version of WordPress.</p><h3 id="which-php-version-is-required" tabindex="-1">Which PHP version is required? <a class="header-anchor" href="#which-php-version-is-required" aria-label="Permalink to &quot;Which PHP version is required?&quot;">‚Äã</a></h3><p>TubeBay requires <strong>PHP 7.4 or later</strong>. We recommend <strong>PHP 8.0+</strong> for the best performance and compatibility.</p><h2 id="connection-sync" tabindex="-1">Connection &amp; Sync <a class="header-anchor" href="#connection-sync" aria-label="Permalink to &quot;Connection &amp; Sync&quot;">‚Äã</a></h2><h3 id="why-should-i-use-google-oauth" tabindex="-1">Why should I use Google OAuth? <a class="header-anchor" href="#why-should-i-use-google-oauth" aria-label="Permalink to &quot;Why should I use Google OAuth?&quot;">‚Äã</a></h3><p>OAuth is the recommended connection method because it is more secure and doesn&#39;t require you to create a Google Cloud project. It uses a secure token to authenticate, which you can revoke at any time.</p><h3 id="how-often-do-videos-sync" tabindex="-1">How often do videos sync? <a class="header-anchor" href="#how-often-do-videos-sync" aria-label="Permalink to &quot;How often do videos sync?&quot;">‚Äã</a></h3><p>By default, TubeBay syncs your video library every 12 hours. You can trigger a manual sync at any time from the <strong>Library</strong> or <strong>Settings</strong> page.</p><h3 id="will-tubebay-slow-down-my-site" tabindex="-1">Will TubeBay slow down my site? <a class="header-anchor" href="#will-tubebay-slow-down-my-site" aria-label="Permalink to &quot;Will TubeBay slow down my site?&quot;">‚Äã</a></h3><p>No. TubeBay is built with performance in mind. It caches your video library using WordPress transients, so fetching videos is instantaneous and doesn&#39;t involve constant remote API calls.</p><h2 id="video-player" tabindex="-1">Video Player <a class="header-anchor" href="#video-player" aria-label="Permalink to &quot;Video Player&quot;">‚Äã</a></h2><h3 id="where-can-i-display-the-video" tabindex="-1">Where can I display the video? <a class="header-anchor" href="#where-can-i-display-the-video" aria-label="Permalink to &quot;Where can I display the video?&quot;">‚Äã</a></h3><p>You can display the video in several locations on the product page, including after the summary, in a new tab, or using shortcodes for custom locations.</p><h3 id="does-the-player-work-on-mobile" tabindex="-1">Does the player work on mobile? <a class="header-anchor" href="#does-the-player-work-on-mobile" aria-label="Permalink to &quot;Does the player work on mobile?&quot;">‚Äã</a></h3><p>Yes, the TubeBay player is fully responsive and uses the official YouTube IFrame API to ensure smooth playback across all devices.</p><h2 id="support" tabindex="-1">Support <a class="header-anchor" href="#support" aria-label="Permalink to &quot;Support&quot;">‚Äã</a></h2><h3 id="where-can-i-get-help" tabindex="-1">Where can I get help? <a class="header-anchor" href="#where-can-i-get-help" aria-label="Permalink to &quot;Where can I get help?&quot;">‚Äã</a></h3><ul><li>Use the support forum on the <a href="https://wordpress.org/support/plugin/tubebay/" target="_blank" rel="noreferrer">WordPress.org plugin page</a>.</li><li>Report bugs via the <a href="https://github.com/wpanchorbay/tubebay/issues" target="_blank" rel="noreferrer">GitHub Issue Tracker</a>.</li><li>For premium support, visit our <a href="https://wpanchorbay.com/support/" target="_blank" rel="noreferrer">official website</a>.</li></ul>',24)])])}const m=a(i,[["render",s]]);export{p as __pageData,m as default};
